from page_client import collect_items


def test_collection_crosses_archive_boundary_with_rich_metadata():
    start = "https://api.example.test/v1/archive/page-one"
    second = (
        "https://api.example.test/v1/catalog"
        "?page=2&fields=id,name"
    )
    pages = {
        start: (
            '{"items": [{"id": 10}]}',
            {
                "Link": (
                    '<../catalog?page=2&fields=id,name>; '
                    'title="priority; recent, batch"; '
                    'type="application/json"; rel="alternate next", '
                    '<page-zero>; rel="prev"'
                )
            },
        ),
        second: (
            '{"items": [{"id": 20}]}',
            {},
        ),
    }

    assert collect_items(start, pages.__getitem__) == (
        {"id": 10},
        {"id": 20},
    )
